ItemConfig = {}
ItemConfig.Items = {}
ItemConfig.ItemType = {
    Weapon = 1,
    Defense = 2
}
ItemConfig.snowBallDamage = 0

function ItemConfig:init(config)
    for _, item in pairs(config) do
        local pItem = {}
        pItem.id = item.id
        pItem.itemId = item.itemId
        pItem.canPile = true
        if item.canPile and tonumber(item.canPile) == 0 then
            pItem.canPile = false
        end
        pItem.meta = tonumber(item.meta)
        pItem.property = StringUtil.split(item.property, "#")
        pItem.enchantments = self:getEnchantment(item.enchantment, item.lv)
        pItem.type = tonumber(item.type) or 0
        pItem.damage = tonumber(item.damage) or 0
        self.Items[item.id] = pItem
        if not pItem.canPile then
            self:setItemMaxStackSize(item.itemId, 1)
        end
        if tonumber(pItem.itemId) == ItemID.SNOWBALL then
            self.snowBallDamage = pItem.damage
        end
    end
end

function ItemConfig:getPropertiesByIdAndMeta(id, meta)
    for _, item in pairs(self.Items) do
        if item.itemId == tostring(id) and item.meta == tonumber(meta) then
            return item.property
        end
    end
    return nil
end

function ItemConfig:getItemByIdAndMeta(itemId, meta)
    for _, item in pairs(self.Items) do
        if item.itemId == tostring(itemId) and item.meta == tonumber(meta) then
            return item
        end
    end
    return nil
end

function ItemConfig:getItemById(id)
    local item = self.Items[tostring(id)]
    if item ~= nil then
        return item
    end
    return nil
end

function ItemConfig:getTypeByIdAndMeta(itemId, meta)
    for _, item in pairs(self.Items) do
        if item.itemId == tostring(itemId) and item.meta == tonumber(meta) then
            return item.type
        end
    end
    return 0
end

function ItemConfig:getEnchantment(enchantment, lv)
    local result = {}
    local enchantments = StringUtil.split(enchantment, "#")
    local lvs = StringUtil.split(lv, "#")
    if enchantments == nil then
        return result
    end
    for index, id in pairs(enchantments) do
        local item = {}
        item[1] = tonumber(id)
        item[2] = tonumber(lvs[index])
        table.insert(result, item)
    end
    return result
end

function ItemConfig:setItemMaxStackSize(itemId, itemMaxStackSize)
    local itemStack = Item.getItemById(itemId)
    if itemStack ~= nil then
        itemStack:setMaxStackSize(itemMaxStackSize)
    end
end

function ItemConfig:getItemDamage(item, damage)
    local pItem = self:getItemByIdAndMeta(item.id, item.meta)
    if pItem == nil then
        pItem = self:getItemById(item.id)
    end
    if pItem == nil or pItem.damage == 0 then
        return damage
    end
    return pItem.damage
end